+fn token_has_inline_code(token: &[u8]) -> bool {
+    let mut i = 0;
+    while i < token.len() {
+        match token[i] {
+            b'`' => return true,
+            b'$' if i + 1 < token.len() && token[i + 1] == b'(' => return true,
+            b'\\' => {
+                i = (i + 2).min(token.len());
+            }
+            _ => {
+                i += 1;
+            }
+        }
+    }
